#!/usr/bin/env node

/**
 * Bundles wiki/pages/*.md into src/wiki-data.ts
 * Run before tsc to embed wiki content in the npm package.
 */

import { readFileSync, readdirSync, writeFileSync, existsSync } from "fs";
import { join, basename, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
// Look for pages in the repo root first, then fall back to ../wiki/pages
const localDir = join(__dirname, "..", "pages");
const parentDir = join(__dirname, "..", "..", "wiki", "pages");
const wikiDir = existsSync(localDir) ? localDir : parentDir;
const outFile = join(__dirname, "..", "src", "wiki-data.ts");

if (!existsSync(wikiDir)) {
  console.error(`Wiki pages directory not found: ${wikiDir}`);
  process.exit(1);
}

const files = readdirSync(wikiDir).filter((f) => f.endsWith(".md"));
const articles = [];

for (const file of files) {
  const content = readFileSync(join(wikiDir, file), "utf-8");
  const slug = basename(file, ".md");

  // Extract title (first # heading)
  const titleMatch = content.match(/^#\s+(.+)$/m);
  const title = titleMatch ? titleMatch[1].trim() : slug;

  // Extract summary (first > blockquote)
  const summaryMatch = content.match(/^>\s+(.+)$/m);
  const summary = summaryMatch ? summaryMatch[1].trim() : "";

  // Extract domain from slug prefix
  const domainMap = {
    gdpr: "GDPR",
    "ai-act": "EU AI Act",
    ccpa: "CCPA/CPRA",
    "us-state": "US Privacy",
    license: "Software Licensing",
    wcag: "Web Accessibility",
    eaa: "Web Accessibility",
  };
  const domain =
    Object.entries(domainMap).find(([prefix]) =>
      slug.startsWith(prefix)
    )?.[1] || "General";

  // Extract cross-references
  const crossRefs = [];
  const refRegex = /\[\[([^\]]+)\]\]/g;
  let match;
  while ((match = refRegex.exec(content)) !== null) {
    crossRefs.push(match[1]);
  }

  // Extract key points section
  const keyPointsMatch = content.match(
    /## Key Points\n([\s\S]*?)(?=\n## |\n$)/
  );
  const keyPoints = keyPointsMatch ? keyPointsMatch[1].trim() : "";

  articles.push({ slug, title, summary, domain, content, crossRefs, keyPoints });
}

// Compute stats before generating
const totalWords = articles.reduce((sum, a) => sum + a.content.split(/\s+/).length, 0);

// Generate TypeScript file
const ts = `// Auto-generated by scripts/bundle-wiki.js — do not edit manually
// Generated: ${new Date().toISOString()}
// Articles: ${articles.length}

export interface WikiArticle {
  slug: string;
  title: string;
  summary: string;
  domain: string;
  content: string;
  crossRefs: string[];
  keyPoints: string;
}

export const WIKI_ARTICLES: WikiArticle[] = ${JSON.stringify(articles, null, 2)};

export const WIKI_DOMAINS = ${JSON.stringify([...new Set(articles.map((a) => a.domain))], null, 2)};

export const WIKI_STATS = {
  totalArticles: ${articles.length},
  totalWords: ${totalWords},
  domains: ${JSON.stringify(
    [...new Set(articles.map((a) => a.domain))].map((d) => ({
      name: d,
      count: articles.filter((a) => a.domain === d).length,
    })),
    null,
    2
  )},
  generatedAt: "${new Date().toISOString()}",
};
`;

writeFileSync(outFile, ts, "utf-8");
console.log(
  `Bundled ${articles.length} wiki articles (${articles.reduce((s, a) => s + a.content.split(/\s+/).length, 0)} words) → ${outFile}`
);
